## Implementation

```rust
pub fn format_system_message_typed<S: Signature>(&self) -> Result<String, minijinja::Error> {
    let mut parts = Vec::new();

    // 1. Field descriptions (inputs and outputs)
    parts.push(self.format_field_descriptions_typed::<S>());

    // 2. Interaction structure (marker template)
    parts.push(self.format_field_structure_typed::<S>());

    // 3. BAML schema for output
    let schema = S::output_format_content()
        .render(RenderOptions::default())?
        .unwrap_or_default();

    if !schema.is_empty() {
        parts.push(format!("Answer in this schema:\n{}\n", schema));
    }

    // 4. Instruction
    let instruction = S::instruction();
    if !instruction.is_empty() {
        parts.push(instruction.to_string());
    }

    Ok(parts.join("\n\n"))
}

fn format_field_descriptions_typed<S: Signature>(&self) -> String {
    let mut lines = Vec::new();

    // Inputs
    for (i, field) in S::input_fields().iter().enumerate() {
        let type_name = (field.type_ir)().diagnostic_repr();
        let mut line = format!("{}. {} ({})", i + 1, field.name, type_name);
        if !field.description.is_empty() {
            line.push_str(": ");
            line.push_str(field.description);
        }
        lines.push(line);
    }

    // Outputs
    let offset = S::input_fields().len();
    for (i, field) in S::output_fields().iter().enumerate() {
        let type_name = (field.type_ir)().diagnostic_repr();
        let mut line = format!("{}. {} ({})", offset + i + 1, field.name, type_name);
        if !field.description.is_empty() {
            line.push_str(": ");
            line.push_str(field.description);
        }
        lines.push(line);
    }

    lines.join("\n")
}

fn format_field_structure_typed<S: Signature>(&self) -> String {
    let mut lines = vec![
        "All interactions will be structured as follows:".to_string(),
        String::new(),
    ];

    // Input markers
    for field in S::input_fields() {
        lines.push(format!("[[ ## {} ## ]]", field.name));
        lines.push(field.name.to_string());
        lines.push(String::new());
    }

    // Output markers
    for field in S::output_fields() {
        lines.push(format!("[[ ## {} ## ]]", field.name));
        lines.push(field.name.to_string());
        lines.push(String::new());
    }

    lines.push("[[ ## completed ## ]]".to_string());

    lines.join("\n")
}
```

## BAML Schema Example

For `__QAOutput { answer: String, confidence: f32 }`:

```
{
  answer: string,
  confidence: float,
}
```

(Actual format depends on RenderOptions)

